checks.expected:
.resource-table :is(th, td) {
  padding: 0.75rem;
  border: 1px solid #64748b;
  text-align: start;
}

.resource-table caption {
  padding-block: 0.75rem;
  font-size: 1.25rem;
  font-weight: 800;
  text-align: start;
}

@media (forced-colors: active) {
  .resource-table :is(th, td) {
    border-color: CanvasText;
  }
  .resource-action:focus-visible {
    outline-color: Highlight;
  }
}

@media print {
  .table-region {
    overflow: visible;
  }
  .resource-table {
    min-inline-size: 0;
  }
  .resource-table tr {
    break-inside: avoid;
  }
}
